30	          MaskMode MASK_MODE, typename AttentionVariant, typename Params>
31	cudaError_t BatchPagedAttentionPersistent(const Params params_1, const Params params_2,
32	                                          const uint32_t num_blks_x, const uint32_t num_blks_y,
