1139	struct HolisticPlanInfo {
1140	  int64_t num_blks_x;
1141	  int64_t num_blks_y;
1142	  struct {
1143	    int64_t q_indptr_offset;
1144	    int64_t kv_indptr_offset;
1145	    int64_t partial_indptr_offset;
1146	    int64_t q_len_offset;
1147	    int64_t kv_len_offset;
1148	    int64_t q_start_offset;
1149	    int64_t kv_start_offset;
1150	    int64_t kv_end_offset;
1151	    int64_t kv_head_idx_offset;
1152	    int64_t work_indptr_offset;
1153	  } tasks[NUM_TASKS];
1154	  int64_t len_kv_chunk_offset;
1155	  int64_t partial_o_offset;
1156	  int64_t partial_lse_offset;
1157	  int64_t merge_indptr_offset;
1158	  int64_t merge_o_indices_offset;
1159	  int64_t num_qo_len_offset;
1160	
1161	  static constexpr uint32_t NUM_TASK_ARGS = 10;
1162	  static constexpr uint32_t NUM_SHARED_ARGS = 8;
1163	
1164	  std::vector<int64_t> ToVector() const {
1165	    std::vector<int64_t> vec;
1166	    vec.push_back(num_blks_x);
1167	    vec.push_back(num_blks_y);
1168	    for (uint32_t i = 0; i < NUM_TASKS; ++i) {
1169	      vec.push_back(tasks[i].q_indptr_offset);
1170	      vec.push_back(tasks[i].kv_indptr_offset);
1171	      vec.push_back(tasks[i].partial_indptr_offset);
1172	      vec.push_back(tasks[i].q_len_offset);
1173	      vec.push_back(tasks[i].kv_len_offset);
1174	      vec.push_back(tasks[i].q_start_offset);
1175	      vec.push_back(tasks[i].kv_start_offset);
1176	      vec.push_back(tasks[i].kv_end_offset);
1177	      vec.push_back(tasks[i].kv_head_idx_offset);
1178	      vec.push_back(tasks[i].work_indptr_offset);
1179	    }
1180	    vec.push_back(len_kv_chunk_offset);
1181	    vec.push_back(partial_o_offset);
1182	    vec.push_back(partial_lse_offset);
1183	    vec.push_back(merge_indptr_offset);
1184	    vec.push_back(merge_o_indices_offset);
1185	    vec.push_back(num_qo_len_offset);
1186	    return vec;
1187	  }
1188	
1189	  void FromVector(const std::vector<int64_t>& vec) {
1190	    if (vec.size() != NUM_SHARED_ARGS + NUM_TASKS * NUM_TASK_ARGS) {
1191	      std::ostringstream err_msg;
1192	      err_msg << "HolisticPlanInfo::FromVector: vec.size() should be "
1193	              << NUM_SHARED_ARGS + NUM_TASKS * NUM_TASK_ARGS << ", but got " << vec.size();
1194	      FLASHINFER_ERROR(err_msg.str());
1195	    }
1196	    num_blks_x = vec[0];
1197	    num_blks_y = vec[1];
1198	    for (uint32_t i = 0; i < NUM_TASKS; ++i) {
1199	      tasks[i].q_indptr_offset = vec[2 + i * NUM_TASK_ARGS + 0];
1200	      tasks[i].kv_indptr_offset = vec[2 + i * NUM_TASK_ARGS + 1];
1201	      tasks[i].partial_indptr_offset = vec[2 + i * NUM_TASK_ARGS + 2];
1202	      tasks[i].q_len_offset = vec[2 + i * NUM_TASK_ARGS + 3];
